<?php require __DIR__.'/helpers.php';$in=input_json();$pdo->prepare('INSERT INTO mantenimientos(cliente,area,fecha_programada,observacion,estado_mantenimiento,estado) VALUES(?,?,?,?,?,1)')->execute([$in['cliente']??'',$in['area']??'',$in['fecha_programada']??null,$in['observacion']??'','Programado']);$mid=$pdo->lastInsertId();if(isset($in['actividades'])&&is_array($in['actividades'])){foreach($in['actividades'] as $a){$pdo->prepare('INSERT INTO mantenimiento_actividades(mantenimiento_id,actividad,realizado) VALUES(?,?,1)')->execute([$mid,$a]);}}responder(true,'Mantenimiento guardado');
